  border-radius: var(--radius-pill);
  min-height: 2rem;
  padding: 0.35rem 0.65rem;
}

.note-editor-mode-toggle {
  align-items: center;
  background: rgba(241, 245, 249, 0.9);
  border: 1px solid rgba(100, 116, 139, 0.18);
  border-radius: var(--radius-pill);
  color: var(--ink-muted);
  cursor: pointer;
  display: inline-flex;
  font-family: var(--font-ui);
  font-size: 0.72rem;
  font-weight: 700;
  justify-content: center;
  letter-spacing: 0.14em;
  min-height: 2.5rem;
  padding: 0.55rem 0.85rem;
  text-transform: uppercase;
  transition:
    background-color 140ms ease,
    border-color 140ms ease,
    color 140ms ease,
    transform 140ms ease,
    box-shadow 140ms ease;
}

.note-editor-mode-toggle:hover {
  background: rgba(255, 255, 255, 0.96);
  border-color: rgba(50, 72, 99, 0.22);
  color: var(--accent-strong);
}

.note-editor-mode-toggle:focus-visible {
  outline: 2px solid rgba(50, 72, 99, 0.28);
  outline-offset: 2px;
}

.note-editor-mode-toggle-active {
  background: rgba(50, 72, 99, 0.11);
  border-color: rgba(50, 72, 99, 0.22);
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.78);
  color: var(--accent-strong);
}

.note-editor-workbench-body,
.note-editor-pane,
.note-editor-preview-frame,
.note-editor-preview-head {
  display: grid;
}

.note-editor-workbench-body {
  gap: 0;
}

.note-editor-pane {
  min-width: 0;
}

.note-editor-pane-hidden {
  display: none;
}

.note-editor-surface {
  background:
    linear-gradient(180deg, rgba(248, 250, 252, 0.86), rgba(241, 245, 249, 0.98)),
    rgba(248, 250, 252, 0.96);
  display: grid;
  grid-template-columns: auto minmax(0, 1fr);
  min-height: clamp(21rem, 48vh, 28rem);
}

.note-editor-preview-frame {
  background:
    linear-gradient(180deg, rgba(252, 253, 255, 0.92), rgba(241, 245, 249, 0.98)),
    rgba(255, 255, 255, 0.96);
  border-top: 1px solid rgba(100, 116, 139, 0.12);
  gap: var(--space-4);
  min-height: clamp(21rem, 48vh, 28rem);
  padding: 1rem 1.15rem 1.25rem;
}

.note-editor-preview-head {
  align-items: center;
  border-bottom: 1px solid rgba(100, 116, 139, 0.12);
  gap: 0.9rem;
  grid-template-columns: minmax(0, 1fr);
  padding-bottom: 0.9rem;
}

.note-editor-preview-head strong {
  color: var(--accent-strong);
  display: block;
  font-family: var(--font-ui);
  font-size: var(--text-xs);
  letter-spacing: 0.16em;
  margin-bottom: 0.2rem;
  text-transform: uppercase;
}

.note-editor-preview-head span,
.note-editor-preview-mode-note {
  color: var(--ink-muted);
  font-size: var(--text-sm);
}

.note-editor-preview-mode-note {
  justify-self: start;
}

.note-editor-pane-preview h2 {
  font-size: clamp(1.4rem, 2.35vw, 1.9rem);
  line-height: 1.02;
  margin: 0;
}

.note-editor-pane-preview .markdown-preview {
  min-height: 0;
}

.note-editor-gutter {
  background:
    linear-gradient(180deg, rgba(226, 232, 240, 0.66), rgba(226, 232, 240, 0.38)),
    rgba(226, 232, 240, 0.72);
  border-right: 1px solid rgba(100, 116, 139, 0.14);
  color: var(--ink-faint);
  font-family: var(--font-mono);
  font-size: 0.76rem;
  letter-spacing: 0.03em;
  min-width: 3.45rem;
  overflow: hidden;
  padding: 1rem 0.55rem 1.15rem 0.7rem;
  text-align: right;
}

.note-editor-gutter-track {
  display: grid;
  gap: 0;
  line-height: 1.65;
}

